import{_ as a,c as i,a as n,o as e}from"./app-CEcM0piI.js";const l={};function p(d,s){return e(),i("div",null,s[0]||(s[0]=[n(`<p>系统给虚拟内存的每个存储单元分配了一个编号，从0x00 00 00 00 ~0xff ff ff ff这个编号咱们称之为地址 指针就是地址</p><p>指针变量:是个变量，是个指针变量，即这个变量用来存放一个地址编号在 32 位平台下，地址总线是 32 位的，所以地址是 32 位编号，所以指针变量是 32 位的即 4 个字节。</p><p>注意:1: 无论什么类型的地址，都是存储单元的编号，在 32 位平台下都是 4 个字节，即任何类型的指针变量都是 4 个字节大小 对应类型的指针变量，只能存放对应类型的变量的地址举例:整型的指针变量，只能存放整型变量的地址</p><p>扩展: 字符变量 char ch=&#39;b&#39;; ch 占1个字节，它有一个地址编号，这个地址编号就是 ch 的地址整型变量 inta=0x12 34 56 78; a 占4 个字节，它占有4 个字节的存储单元，有4个地址编号。</p><h1 id="定义" tabindex="-1"><a class="header-anchor" href="#定义"><span>定义</span></a></h1><h3 id="_1-简单的指针变量" tabindex="-1"><a class="header-anchor" href="#_1-简单的指针变量"><span>1.简单的指针变量</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>数据类型 * 指针变量名;</span></span>
<span class="line"><span>int * p;//定义了一个指针变量p</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>在定义指针变量的时候 * 是用来修饰变量的，说明变量 p 是个指针变量，变量名是 p</p><h3 id="_2-关于指针的运算符" tabindex="-1"><a class="header-anchor" href="#_2-关于指针的运算符"><span>2.关于指针的运算符</span></a></h3><p>&amp; 取地址 <span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><semantics><mrow><mo>∗</mo><mtext>取值</mtext></mrow><annotation encoding="application/x-tex">*取值</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:0.6833em;"></span><span class="mord">∗</span><span class="mord cjk_fallback">取值</span></span></span></span></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int a=0x1234abcd;</span></span>
<span class="line"><span>int *p;//在定义指针变量的时候*代表修饰的意思,修饰p是个指针变量</span></span>
<span class="line"><span>p=&amp;a;//把 a 的地址给 p 赋值,&amp;是取地址符</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>p 保存了 a的地址，也可以说p 指向了 a</p><p>p和a 的关系分析: a 的值是 0x1234abcd，假如 a的地址是: 0xbfe8 98 68</p><h3 id="分析" tabindex="-1"><a class="header-anchor" href="#分析"><span>分析</span></a></h3><p>1、在调用的时候 <span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><semantics><mrow><mo>∗</mo></mrow><annotation encoding="application/x-tex">*</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:0.4653em;"></span><span class="mord">∗</span></span></span></span>代表取值的意思，<span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><semantics><mrow><mo>∗</mo></mrow><annotation encoding="application/x-tex">*</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:0.4653em;"></span><span class="mord">∗</span></span></span></span>p 就相当于p 指向的变量，即a, 2、故num-*p和num=a 的效果是一样的。 3、所以说num 的值为0x1234abcd。</p><h3 id="扩展" tabindex="-1"><a class="header-anchor" href="#扩展"><span>扩展</span></a></h3><p>如果在一行中定义多个指针变量，每个指针变量前面都需要加<span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><semantics><mrow><mo>∗</mo></mrow><annotation encoding="application/x-tex">*</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:0.4653em;"></span><span class="mord">∗</span></span></span></span>来修饰</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int*p,*q;//定义了两个整型的指针变量p和q</span></span>
<span class="line"><span>int*p,q;//定义了一个整型指针变量p和整型的变量 q</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int main()</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>	int a= 100, b = 200;</span></span>
<span class="line"><span>	int*p_1,*p_2 = &amp;b;    //表示该变量的类型是一个指针变量，指针变量名是 p_1而不是*p_1</span></span>
<span class="line"><span>	    //p_1 在定义的时候没有赋初值,P_2 赋了初值</span></span>
<span class="line"><span>	p_1= &amp;a;    //p_1先定义后赋值</span></span>
<span class="line"><span>	printf(&quot;%d\\n&quot;, a);</span></span>
<span class="line"><span>	printf(&quot;%d\\n&quot;, *p_1);</span></span>
<span class="line"><span>	return 0;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在定义p_1的时候，因为是个局部变量，局部变量没有赋初值，它的值是随机的，P_1指向哪里不一定所以p_1 就是个野指针。</p><h1 id="分类" tabindex="-1"><a class="header-anchor" href="#分类"><span>分类</span></a></h1><p>按照指针指向的数据的类型来分</p><ol><li>字符指针</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>字符型数据的地址</span></span>
<span class="line"><span>char *p;//定义了一个字符指针变量，只能存放字符型数据的地址编号</span></span>
<span class="line"><span>char ch;</span></span>
<span class="line"><span>p=&amp;ch;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="2"><li>短整型指针</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>short int *p;//定义了一个短整型指针p，只能存放短整型变量的地址</span></span>
<span class="line"><span>short int a;</span></span>
<span class="line"><span>p=&amp;a;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="3"><li>整形指针</li><li>长整型指针</li><li>float型指针</li><li>double型指针</li><li>函数指针</li><li>结构体指针</li><li>指针的指针</li><li>数组的指针</li><li>通用指针</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>void *p；</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>无论什么类型的指针变量，在 32 位系统下，都是 4 个字节 指针只能存放对应类型的变量的地址编号。</p><h1 id="指针与类型" tabindex="-1"><a class="header-anchor" href="#指针与类型"><span>指针与类型</span></a></h1><h1 id="指针与变量" tabindex="-1"><a class="header-anchor" href="#指针与变量"><span>指针与变量</span></a></h1><p>指针可以存放变量的地址编号</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int a=100;</span></span>
<span class="line"><span>int *p;</span></span>
<span class="line"><span>p=&amp;a;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="在程序中-引用变量的方法" tabindex="-1"><a class="header-anchor" href="#在程序中-引用变量的方法"><span>在程序中，引用变量的方法</span></a></h3><p>1、直接通过变量的名称</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int a;</span></span>
<span class="line"><span>a=100;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>2、可以通过指针变量来引用变量</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>imt *p://在定义的时候，*不是取值的意思，而是修饰的意思，修饰 p 是个指针变量</span></span>
<span class="line"><span>p-&amp;a;//取 a的地址给p 赋值，p 保存了 a 的地址，也可以说 p 指向了 a</span></span>
<span class="line"><span>*p= 100;//在调用的时候*是取值的意思，*指针变量 等价于指针指向的变量</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>指针变量在定义的时候可以初始化 对应类型的指针，只能保存对应类型数据的地址，如果想让不同类型的指针相互赋值的时候，需要强制类型转换</p><h1 id="指针与数组" tabindex="-1"><a class="header-anchor" href="#指针与数组"><span>指针与数组</span></a></h1><p>变量存放在内存中，有地址编号，定义的数组，是多个相同类型的变量的集合，每个变量都占内存空间，都有地址编号指针变量当然可以存放数组元素的地址。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int a[5];</span></span>
<span class="line"><span>//int *p =&amp;a[0];</span></span>
<span class="line"><span>int *p;</span></span>
<span class="line"><span>p=&amp;a[0];//指针变量p保存了数组a中第 0个元素的地址，即 ar0的地址</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="数组元素的引用方法2" tabindex="-1"><a class="header-anchor" href="#数组元素的引用方法2"><span>数组元素的引用方法2</span></a></h3><p>方法1: 数组名[下标]</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int a[5]:</span></span>
<span class="line"><span>a[2]=100;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>方法2:指针名加下标</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int a[5];</span></span>
<span class="line"><span>int *p;</span></span>
<span class="line"><span>p=a;</span></span>
<span class="line"><span>p[2]=100://相当于 a[2]=100;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>补充: c 语言规定: 数组的名字就是数组的首地址，即第 0 个元素的地址，就是&amp;a[0]，是个常量。</p><p>方法3: 通过指针变量运算加取值的方法来引用数组的元素</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int a[5];</span></span>
<span class="line"><span>int *p;</span></span>
<span class="line"><span>p=a;</span></span>
<span class="line"><span>*(p+2)=100://也是可以的，相当于 a[2]=100</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>解释:p是第 0个元素的地址，p+2 是 a[2]这个元素的地址 对第二个元素的地址取值，即 a[2]</p><p>方法 4:通过数组名+取值的方法引用数组的元素</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int a [5]:</span></span>
<span class="line"><span>*(a+2)=100://也是可以的，相当于 a[2]=100;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>注意: a+2 是 a[2]的地址。这个地方并没有给 a 赋值</p><h2 id="指针的运算" tabindex="-1"><a class="header-anchor" href="#指针的运算"><span>指针的运算</span></a></h2><h4 id="_1、指针可以加一个整数-往下指几个它指向的变量-结果还是个地址前提-指针指向数组的时候-加一个整数才有意义" tabindex="-1"><a class="header-anchor" href="#_1、指针可以加一个整数-往下指几个它指向的变量-结果还是个地址前提-指针指向数组的时候-加一个整数才有意义"><span>1、指针可以加一个整数,往下指几个它指向的变量，结果还是个地址前提: 指针指向数组的时候，加一个整数才有意义</span></a></h4><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int a[10];</span></span>
<span class="line"><span>int *p;</span></span>
<span class="line"><span>p=a;</span></span>
<span class="line"><span>p+2;//p是 a[0]的地址，p+2 是&amp;a[2]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>假如p 保存的地址编号是 2000 的话，p+2 代表的地址编号是 2008</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>char buf[5];</span></span>
<span class="line"><span>char *q;</span></span>
<span class="line"><span>q=buf;</span></span>
<span class="line"><span>g+2//相当于&amp;buf[2]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>假如:q 中存放的地址编号是 2000 的话，g+2代表的地址编号是 2002</p><h4 id="_2、两个相同类型指针可以比较大小" tabindex="-1"><a class="header-anchor" href="#_2、两个相同类型指针可以比较大小"><span>2、两个相同类型指针可以比较大小</span></a></h4><p>前提: 只有两个相同类型的指针指向同一个数组的元素的时候，比较大小才有意义指向前面元素的指针小于指向后面元素的指针</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#include &lt;stdio.h&gt;</span></span>
<span class="line"><span>int main(int argc, char *argv[])</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>	int a[10];</span></span>
<span class="line"><span>	int *p,*q,n;//如果在一行上定义多个指针变量的，每个变量名前面加//上边一行定义了两个指针 p和g，定义了一个整型的变量n</span></span>
<span class="line"><span>	p=&amp;a[1J;</span></span>
<span class="line"><span>	q=&amp;a[6];</span></span>
<span class="line"><span>	if(p&lt;q){</span></span>
<span class="line"><span>		printf(&quot;p&lt;q\\n&quot;);</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	return 0;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_3、两个相同类型的指针可以做减法" tabindex="-1"><a class="header-anchor" href="#_3、两个相同类型的指针可以做减法"><span>3、两个相同类型的指针可以做减法</span></a></h4><p>前提: 必须是两个相同类型的指针指向同一个数组的元素的时候，做减法才有意义做减法的结果是，两个指针指向的中间有多少个元素</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#include &lt;stdio.h&gt;</span></span>
<span class="line"><span>int main(int argc, char *argv[])</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>	int a[10];</span></span>
<span class="line"><span>	int *p,*q;</span></span>
<span class="line"><span>	p=&amp;a[0];</span></span>
<span class="line"><span>	9=&amp;a[3];</span></span>
<span class="line"><span>	printf(&quot;%d\\n&quot;,q-p);</span></span>
<span class="line"><span>	return 0;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>//结果3</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_4、两个相同类型的指针可以相互赋值" tabindex="-1"><a class="header-anchor" href="#_4、两个相同类型的指针可以相互赋值"><span>4、两个相同类型的指针可以相互赋值</span></a></h4><p>注意:只有相同类型的指针才可以相互赋值 (void *类型的除外)</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int *p;</span></span>
<span class="line"><span>int *q;</span></span>
<span class="line"><span>int a;</span></span>
<span class="line"><span>p=&amp;a://p 保存a的地址，p 指向了变量 a</span></span>
<span class="line"><span>q=p;//用p给q 赋值，q 也保存了a的地址，指向a</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>注意: 如果类型不相同的指针要想相互赋值，必须进行强制类型转换 注意:c 语言规定数组的名字，就是数组的首地址，就是数组第 0 个元素的地址</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int *p;</span></span>
<span class="line"><span>int a[10];</span></span>
<span class="line"><span>p=a; p=&amp;a[0];这两种赋值方法是等价的</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="const修饰指针" tabindex="-1"><a class="header-anchor" href="#const修饰指针"><span>const修饰指针</span></a></h2><h3 id="const-char-str" tabindex="-1"><a class="header-anchor" href="#const-char-str"><span>const char * str</span></a></h3><p>str 指向的内存的内容不能修改 但是 str 的指向是可以改变的</p><h3 id="char-const-str" tabindex="-1"><a class="header-anchor" href="#char-const-str"><span>char * const str</span></a></h3><p>str 是只读的变量，str 不能指向别的地方 但是 str 指向的内存的内容，是有可能可以修改的</p><h3 id="const-char-const-str" tabindex="-1"><a class="header-anchor" href="#const-char-const-str"><span>const char * const str</span></a></h3><p>str不能指向其他地方，指向的内存内容也不能通过str修改</p><h1 id="指针和数组" tabindex="-1"><a class="header-anchor" href="#指针和数组"><span>指针和数组</span></a></h1><h2 id="指针数组" tabindex="-1"><a class="header-anchor" href="#指针数组"><span>指针数组</span></a></h2><h3 id="_1、指针和数组的关系" tabindex="-1"><a class="header-anchor" href="#_1、指针和数组的关系"><span>1、指针和数组的关系</span></a></h3><p>指针可以保存数组元素的地址 可以定义一个数组，数组中有若干个相同类型指针变量，这个数组被称为指针数组</p><p>指针数组本身是个数组，是个指针数组，是若干个相同类型的指针变量构成的集合</p><h3 id="_2、指针数组的定义方法" tabindex="-1"><a class="header-anchor" href="#_2、指针数组的定义方法"><span>2、指针数组的定义方法:</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>类型说明符 * 数组名 [元素个数];</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>imt * p[5];//定义了一个整型的指针数组p，有5个元素 p[o]~p[5].每个元素都是 int*类型的变量</span></span>
<span class="line"><span>int a;</span></span>
<span class="line"><span>p[0]=&amp;a;</span></span>
<span class="line"><span>int b[10];</span></span>
<span class="line"><span>p[1]=&amp;b[5];</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>p[2]、* (p+2)是等价的，都是指针数组中的第2个元素。</p><h2 id="数组指针" tabindex="-1"><a class="header-anchor" href="#数组指针"><span>数组指针</span></a></h2><h3 id="定义方法" tabindex="-1"><a class="header-anchor" href="#定义方法"><span>定义方法:</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>指向的数组的类型 (*指针变量名)[指向的数组的元素个数]</span></span>
<span class="line"><span>int(*p)[5];//定义了一个数组指针变量 p，p指向的是整型的有 5 个元素的数组p+1 往下指 5 个整型，跳过一个有 5 个整型元素的数组</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#include&lt;stdio.h&gt;</span></span>
<span class="line"><span>int main(){</span></span>
<span class="line"><span>int a[3][5];//定义了一个 3 行 5 列的一个二维数组</span></span>
<span class="line"><span>int(*p)[5];//定义一个数组指针变量 p，p+1跳一个有 5 个元素的整型数组printf(&quot;a=%p\\n&quot;,a);//第 0 行的行地址</span></span>
<span class="line"><span>printf(&quot;a+1=%p\\n&quot;a+1);//第 1行的行地址，a和a +1差 20 个字节</span></span>
<span class="line"><span>p=a;</span></span>
<span class="line"><span>printf(&quot;p=%p\\n&quot;,p);</span></span>
<span class="line"><span>printf(&quot;p+1=%p\\n&quot;,p+1);//p+1跳一个有 5 个整型元素的一维数组</span></span>
<span class="line"><span>return 0;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="各种数组指针的定义" tabindex="-1"><a class="header-anchor" href="#各种数组指针的定义"><span>各种数组指针的定义:</span></a></h2><p>1、一维数组指针，加 1后指向下个一维数组</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int(*p)[5]; // int *p[5];</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>配合每行有 5个 int 型元素的二维数组来用</p><p>2、二维数组指针，加 1后指向下个二维数组</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int(*p)[4][5];</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>配合三维数组来用，三维数组中由若干个 4 行 5 列二维数组构成</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int a[3][4][5];</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>3、三维数组指针，加 1后指向下个三维数组</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int(*p)[4][5][6];// p+1 跳一个三维数组:</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>由4个5行6列的二维数组构成的三维数组配合使用</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int a[7][4][5][6];</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>四维数组指针，加1后指向下个四维数组，以此类推。。。。</p><h1 id="注意" tabindex="-1"><a class="header-anchor" href="#注意"><span>注意</span></a></h1><h3 id="指针数组-1" tabindex="-1"><a class="header-anchor" href="#指针数组-1"><span>指针数组</span></a></h3><p>是个数组，有若干个相同类型的指针构成的集合</p><p>int * p[10]; 数组 p有 10 个 int * 类型的指针变量构成，分别是 p[0] ~p[9]</p><h3 id="数组指针-1" tabindex="-1"><a class="header-anchor" href="#数组指针-1"><span>数组指针</span></a></h3><p>本身是个指针，指向一个数组加1跳一个数组 int (* p)[10]; P 是个指针，p 是个数组指针，p 加 1指向下个数组，跳 10 个整形。</p><h3 id="指针的指针" tabindex="-1"><a class="header-anchor" href="#指针的指针"><span>指针的指针:</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int **p;//p 是指针的指针</span></span>
<span class="line"><span>int *q</span></span>
<span class="line"><span>p=&amp;q;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>a 是个 int* 类型的指针，是 a[0]的地址。 &amp;a 变成了数组指针，加 1跳一个 10 个元素的整型一维数组</p><p>在运行程序时，a和&amp;a 所代表的地址编号是一样的，即他们指向同一个存储单元，但是 a和&amp;a 的指针类型不同。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int a[4][5];</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>a+1跳5个整型 (&amp;a)+1跳4行5列( 80 个字节)</p><p>c 语言规定，数组名字取地址，变成了数组指针。加 1跳一个数组</p><h3 id="数组名字和指针变量的区别" tabindex="-1"><a class="header-anchor" href="#数组名字和指针变量的区别"><span>数组名字和指针变量的区别</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int a[5];</span></span>
<span class="line"><span>int *p;</span></span>
<span class="line"><span>p=a;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="相同点" tabindex="-1"><a class="header-anchor" href="#相同点"><span>相同点:</span></a></h4><p>a 是数组的名字，是 a[0]的地址，p=a 即p 保存了 a [0]的地址，即a 和p 都指向 a[0]，所以在引用数组元素的时候，a和p等价</p><p>引用数组元素回顾: a[2]、<em>(a+2)、p[2]、</em>(p+2) 都是对数组a 中 a[2]元素的引用。</p><h4 id="不同点" tabindex="-1"><a class="header-anchor" href="#不同点"><span>不同点:</span></a></h4><p>1、a 是常量、p 是变量可以用等号’=给p 赋值，但是不能用等号给 a 赋值</p><p>2、对 a 取地址，和对 p 取地址结果不同因为 a 是数组的名字，所以对 a 取地址结果为数组指针。 p 是个指针变量，所以对 p 取地址 (&amp;p) 结果为指针的指针</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int a[5]={0,1,2,3,4};</span></span>
<span class="line"><span>int *p=a;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>假如 a[0]的地址为 0x00002000.p 的地址为 0x00003000 1、&amp;p 是指针的指针，为 int ** 类型，结果为 0x00003000，&amp;p +1，往后指向一个 int* 类型的指针，地址编号差 4 2、&amp;a 结果是数组指针，为 int(* )[5]类型，结果还是 0x00002000，&amp;a +1,往后指一个数组(有5个整型元素的一维数组)，地址编号差 20</p><h1 id="指针的指针-1" tabindex="-1"><a class="header-anchor" href="#指针的指针-1"><span>指针的指针</span></a></h1><p>指针的指针，即指针的地址， 定义一个指针变量本身指针变量占 4 个字节，指针变量也有地址编号</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int a=0x12345678;</span></span>
<span class="line"><span>//假如: a的地址是 0x00002000</span></span>
<span class="line"><span>int*p;</span></span>
<span class="line"><span>p =&amp;a;</span></span>
<span class="line"><span>//则 p中存放的是 a的地址编号即 0x00002000</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>因为p也占4 个自己内存，也有它自己的地址编号，及指针变量的地址，即指针的指针假如:指针变量 p 的地址编号是 0x00003000，这个地址编号就是指针的地址我们定义一个变量存放 p 的地址编号，这个变量就是指针的指针</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int**q;</span></span>
<span class="line"><span>q=&amp;p;//q 保存了p的地址，也可以说 q 指向了p则 q 里存放的就是 0x00003000</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="指针和字符串" tabindex="-1"><a class="header-anchor" href="#指针和字符串"><span>指针和字符串</span></a></h1><p>字符串的地址，是第一个字符的地址。如: 字符串“helloworld”的地址，其实是字符串中字符”h”的地址。</p><h2 id="字符串的存储形式-数组、文字常量区、堆" tabindex="-1"><a class="header-anchor" href="#字符串的存储形式-数组、文字常量区、堆"><span>字符串的存储形式: 数组、文字常量区、堆</span></a></h2><h3 id="_1、字符串存放在数组中" tabindex="-1"><a class="header-anchor" href="#_1、字符串存放在数组中"><span>1、字符串存放在数组中</span></a></h3><p>其实就是在内存(栈、静态全局区) 中开辟了一段空间存放字符串</p><p>char string[100]= “Ilove C!” 定义了一个字符数组 string.用来存放多个字符，并且用”I love C!”给 string 数组初始化字符串“Ilove C!”存放在 string 中。</p><p>普通全局数组，内存分配在静态全局区普通局部数组，内存分配在栈区。 静态数组(静态全局数组、静态局部数组)，内存分配在静态全局区</p><h3 id="_2、字符串存放在文字常量区" tabindex="-1"><a class="header-anchor" href="#_2、字符串存放在文字常量区"><span>2、字符串存放在文字常量区</span></a></h3><p>在文字常量区开辟了一段空间存放字符串，将字符串的首地址付给指针变量。</p><p>char* str = “I love C!” 定义了一个指针变量 str,只能存放字符地址编号Ilove C! 这个字符串中的字符不是存放在 s 指针变量中。sT 只是存放了字符I的地址编号，“I love C!”存放在文字常量区</p><h3 id="_3、字符串存放在堆区" tabindex="-1"><a class="header-anchor" href="#_3、字符串存放在堆区"><span>3、字符串存放在堆区</span></a></h3><p>使用 malloc 等函数在堆区申请空间，将字符串拷贝到堆区</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>char * st =(char*)malloc(10*sizeoD;//动态申请了 10 个字节的存储空间，首地址给 str 赋值。</span></span>
<span class="line"><span>strcpy(st,&quot;I love C&quot;); //将字符串“ Ilove C!”拷贝到 s 指向的内存里</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="字符串的可修改性" tabindex="-1"><a class="header-anchor" href="#字符串的可修改性"><span>字符串的可修改性</span></a></h2><p>字符串内容是否可以修改，取决于字符串存放在哪里</p><p>1、存放在数组中的字符串的内容是可修改的</p><p>注:数组没有用 const 修饰</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>char str[100]=&quot;I love C!&quot;;</span></span>
<span class="line"><span>str[0]=“y’://正确可以修改的</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>2、文字常量区里的内容是不可修改的</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>char *str=&quot;I love C!&quot;</span></span>
<span class="line"><span>*st =&#39;y’://错误，I存放在文字常量区，不可修改</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>1、str 指向文字常量区的时候，它指向的内存的内容不可被修改。 2、st 是指针变量可以指向别的地方，即可以给 str 重新赋值，让它指向别的地方。</p><p>3、堆区的内容是可以修改的</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>char *str =(char*)malloc(10);</span></span>
<span class="line"><span>strcpy(str,&quot;I love c&quot;)</span></span>
<span class="line"><span>*st=&#39;y&#39;;//正确，可以，因为堆区内容是可修改的</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>1、str 指向堆区的时候，st 指向的内存内容是可以被修改的。 2、str 是指针变量，也可以指向别的地方。即可以给 str 重新赋值，让它指向别的地方</p><p>str 指针指向的内存能不能被修改，要看 str 指向哪里 st 指向文字常量区的时候，内存里的内容不可修改 str 指向数组 (非 const ,修饰)、堆区的时候，它指向内存的内容是可以修改</p><h2 id="初始化" tabindex="-1"><a class="header-anchor" href="#初始化"><span>初始化:</span></a></h2><p>1.字符数组初始化</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>char buf aver[20]=&quot;hello world&quot;;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>2.指针指向文字常量区，初始化</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>char *buf point=&quot;hello world&quot;;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>3、指针指向堆区，堆区存放字符串。</p><p>不能初始化，只能先给指针赋值，让指针指向堆区，再使用 strcpy、scanf 等方法把字符拷贝到堆区</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>char *buf heap;</span></span>
<span class="line"><span>buf heap=(char *)malloc(15);</span></span>
<span class="line"><span>strcpy(buf heap,&quot;hello world&quot;);</span></span>
<span class="line"><span>scanf(s’,buf heap);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="使用时赋值" tabindex="-1"><a class="header-anchor" href="#使用时赋值"><span>使用时赋值</span></a></h2><h3 id="_1、字符数组-使用-scanf或者-strcpy" tabindex="-1"><a class="header-anchor" href="#_1、字符数组-使用-scanf或者-strcpy"><span>1、字符数组:使用 scanf或者 strcpy</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>char buf[20]=&quot;hello world&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>buf=&quot;hello kitty&quot;;//错误,因为字符数组的名字是个常量.不能用等号给常量赋值。</span></span>
<span class="line"><span>strcpy(buf,&quot;hello kitty&quot;);//正确，数组中的内容是可以修改的</span></span>
<span class="line"><span>scanf(&quot;%s&quot;,buf);//正确，数组中的内容是可以修改的</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2、指针指向文字常量区" tabindex="-1"><a class="header-anchor" href="#_2、指针指向文字常量区"><span>2、指针指向文字常量区</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>char *buf point =“hello world”;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1) buf point=&quot;hello kitty&quot;;//正确buf point 指向另一个字符串</span></span>
<span class="line"><span>2) strcpy(buf point,&quot;hello kitty&quot;);//错误，这种情况，buf point 指向的是文字常量区，内容只读当指针指向文字常量区的时候，不能通过指针修改文字常量区的内容。</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-指针指向堆区-堆区存放字符串" tabindex="-1"><a class="header-anchor" href="#_3-指针指向堆区-堆区存放字符串"><span>3.指针指向堆区，堆区存放字符串</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>char *buf heap;</span></span>
<span class="line"><span>buf_heap=(char *)malloc(15);</span></span>
<span class="line"><span>strcpy(buf_heap,&quot;hello world&quot;);</span></span>
<span class="line"><span>scanf(&quot;%s&quot;,buf heap);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="指针和函数" tabindex="-1"><a class="header-anchor" href="#指针和函数"><span>指针和函数</span></a></h1><h1 id="指针作为函数的参数" tabindex="-1"><a class="header-anchor" href="#指针作为函数的参数"><span>指针作为函数的参数</span></a></h1><p>给被调函数传数值，只能改变被调函数形参的值，不能改变主调函数实参的值</p><p>要想在改变实参的值要传地址进去</p><p>调用函数的时候传变量的地址，在被调函数中通过*+地址来改变主调函数中的变量的值</p><h2 id="给函数传数组" tabindex="-1"><a class="header-anchor" href="#给函数传数组"><span>给函数传数组</span></a></h2><p>给函数传数组的时候，没法一下将数组的内容作为整体传进去只能传数组名进去 数组名就是数组的首地址，即只能把数组的地址传进去 也就是说，只能传一个4 个字节大小的地址编号进去</p><h2 id="函数返回指针" tabindex="-1"><a class="header-anchor" href="#函数返回指针"><span>函数返回指针</span></a></h2><p>返回地址的时候，地址指向的内存的内容不能释放如果返回的指针指向的内容已经被释放了，返回这个地址，也没有意义了. 可以在内容前加一个static</p><p>指针指向文字常量区的地址也可以</p><p>返回堆内存的地址（堆内存一直存在，直到程序结束）</p><h1 id="函数指针" tabindex="-1"><a class="header-anchor" href="#函数指针"><span>函数指针:</span></a></h1><p>定义的函数，在运行程序的时候，会将函数的指令加载到内存的代码段。所以函数也有起始地址。 函数的名字就是函数的首地址，即函数的入口地址就可以定义一个指针变量，来存放函数的地址。这个指针变量就是函数指针变量。</p><h2 id="应用" tabindex="-1"><a class="header-anchor" href="#应用"><span>应用</span></a></h2><p>函数指针用来保存函数的入口地址。 在项目开发中，经常需要编写或者调用带函数指针参数的函数。 比如Linux 系统中创建多线程的函数，它有个参数就是函数指针，接收线程函数的入口地址，即线程创建线程成功后，新的任务执行线程函数。</p><h2 id="函数指针变量的定义" tabindex="-1"><a class="header-anchor" href="#函数指针变量的定义"><span>函数指针变量的定义</span></a></h2><p>返回值类型(* 函数指针变量名)(形参列表);</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int(*p)(int，int)://定义了一个函数指针变量pp 指向的函数必须有一个整型的返回值，有两个整型参数。</span></span>
<span class="line"><span>int max(int x,int y){</span></span>
<span class="line"><span></span></span>
<span class="line"><span>};</span></span>
<span class="line"><span></span></span>
<span class="line"><span>int min(int x,int y){</span></span>
<span class="line"><span></span></span>
<span class="line"><span>};</span></span>
<span class="line"><span></span></span>
<span class="line"><span>//可以用这个p 存放这类函数的地址</span></span>
<span class="line"><span>p=max;</span></span>
<span class="line"><span>p-min;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>int main(){</span></span>
<span class="line"><span>	int num=max(3,5);//通过函数的名字去调函数(最常用的)</span></span>
<span class="line"><span>	//可以通过函数指针变量去调用</span></span>
<span class="line"><span>	int num1=(*p)(10,20);//等价于 num = min(10,20)</span></span>
<span class="line"><span>};</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><h2 id="函数指针数组" tabindex="-1"><a class="header-anchor" href="#函数指针数组"><span>函数指针数组</span></a></h2><h4 id="概念" tabindex="-1"><a class="header-anchor" href="#概念"><span>概念</span></a></h4><p>由若干个相同类型的函数指针变量构成的集合，在内存中连续的顺序存储。函数指针数组是个数组，它的每个元素都是一个函数指针变量。</p><h4 id="定义方法-1" tabindex="-1"><a class="header-anchor" href="#定义方法-1"><span>定义方法</span></a></h4><p>指针类型名(* 数组名[元素个数])(形参列表) int(* p[5])(int,int); 定义了一个函数指针数组，有 5 个元素 p[o]~p[4]，每个元素都是函数指针变量每个函数指针变量指向的函数，必须有整型的返回值，两个整型参数。</p><h1 id="易混淆的指针" tabindex="-1"><a class="header-anchor" href="#易混淆的指针"><span>易混淆的指针</span></a></h1><h2 id="int-f-void" tabindex="-1"><a class="header-anchor" href="#int-f-void"><span>int * f(void);</span></a></h2><p><span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><semantics><mrow><mo>∗</mo><mi>f</mi></mrow><annotation encoding="application/x-tex">*f</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:0.8889em;vertical-align:-0.1944em;"></span><span class="mord">∗</span><span class="mord mathnormal" style="margin-right:0.10764em;">f</span></span></span></span>没有用括号括起来它是个函数的声明，声明的这个函数返回值为 int* 类型的。</p><h2 id="int-f-void-1" tabindex="-1"><a class="header-anchor" href="#int-f-void-1"><span>int (* f)(void)</span></a></h2><p><span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><semantics><mrow><mo>∗</mo><mi>f</mi></mrow><annotation encoding="application/x-tex">*f</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:0.8889em;vertical-align:-0.1944em;"></span><span class="mord">∗</span><span class="mord mathnormal" style="margin-right:0.10764em;">f</span></span></span></span>用括号括起来了，* 修饰 f说明，f是个指针变量。f是个函数指针变量，存放函数的地址，它指向的函数，必须有一个 int 型的返回值，没有参数。</p><h1 id="特殊指针" tabindex="-1"><a class="header-anchor" href="#特殊指针"><span>特殊指针</span></a></h1><h2 id="void-通用指针" tabindex="-1"><a class="header-anchor" href="#void-通用指针"><span>void* 通用指针</span></a></h2><p>任何类型的地址都可以给 void* 类型的指针变量赋值。</p><h2 id="null" tabindex="-1"><a class="header-anchor" href="#null"><span>NULL</span></a></h2><p>空指针: char* p=NULL 可以认为 p 哪里都不指向，也可以认为 p 指向内存编号为 0的存储单位在p的四个字节中，存放的是 0x00 00 00 00一般NULL 用在给指针初始化。</p><h1 id="函数指针-1" tabindex="-1"><a class="header-anchor" href="#函数指针-1"><span>函数指针</span></a></h1><p>函数名就是函数的地址</p>`,207)]))}const r=a(l,[["render",p]]),h=JSON.parse('{"path":"/cpp/c/4/","title":"4 指针","lang":"zh-CN","frontmatter":{"title":"4 指针","createTime":"2025/04/05 12:12:26","permalink":"/cpp/c/4/"},"readingTime":{"minutes":18.27,"words":5481},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/C++/C/4 指针.md","headers":[]}');export{r as comp,h as data};
